import{_ as t,o as a,c as i,a6 as r}from"./chunks/framework.DtxWasON.js";const n="/assets/mainchain/streams/Create.png",o="/assets/mainchain/streams/Create_2.png",s="/assets/mainchain/streams/Stream_Info.png",l="/assets/mainchain/streams/Stream_Info_as_receiver.png",h="/assets/mainchain/streams/Tx_History.png",m="/assets/mainchain/streams/Update_Flow_Rate_1.png",c="/assets/mainchain/streams/Update_Flow_Rate_2.png",d="/assets/mainchain/streams/Cancel.png",p="/assets/mainchain/streams/Claim.png",S=JSON.parse('{"title":"Payment Streams UI","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/streams/ui.md","filePath":"mainchain/streams/ui.md"}'),u={name:"mainchain/streams/ui.md"};function f(w,e,g,b,y,v){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="payment-streams-ui" tabindex="-1">Payment Streams UI <a class="header-anchor" href="#payment-streams-ui" aria-label="Permalink to &quot;Payment Streams UI&quot;">​</a></h1><p>The Unification Foundation has deployed a fully functional, proof of concept Payment Streams UI:</p><p><a href="https://streams.unification.io" target="_blank" rel="noreferrer">streams.unification.io</a></p><p><img src="'+n+'" alt="Create Stream" title="Create Stream"></p><p>Using the UI, it’s possible to interact with all the features of the Payment Streams module:</p><ul><li>Creating a stream</li><li>Modifying a stream</li><li>Withdrawing (claiming) from a stream</li><li>Cancelling a stream</li><li>Querying a stream (current state on-chain)</li><li>View the full Tx history for a stream (querying events emitted for a stream)</li></ul><h2 id="creating-a-stream" tabindex="-1">Creating a Stream <a class="header-anchor" href="#creating-a-stream" aria-label="Permalink to &quot;Creating a Stream&quot;">​</a></h2><p>In order to create a new payment stream, you will need a few bits of information:</p><ul><li>The receiver wallet address</li><li>The amount you want to stream and the frequency</li><li>Enough FUND in your wallet to cover the deposit and the transaction fee</li></ul><p>In this example, we’re creating a stream for 100 FUND/month. Once the details are entered, the flow rate is automatically calculated and displayed for confirmation.</p><p><img src="'+o+'" alt="Create Stream" title="Create Stream"></p><p>Before broadcasting the transaction, the UI will display the following information:</p><ul><li>The receiving wallet address</li><li>The amount you wish to deposit (this can be modified before sending the transaction)</li><li>The calculated flow rate (in both nund/second and FUND/second</li><li>The time and date the current deposit amount will run out (effectively ending the stream). This will automatically update if the Deposit amount is modified before sending the transaction, to show the effect of adding more/less deposit.</li></ul><p>When the &quot;Create&quot; button is clicked, your selected wallet provider (for example Keplr) will pop up asking you to verify, sign and broadcast the transaction.</p><p>If successful, the UI will display the transaction hash with a link to the block explorer.</p><p>Behind the scenes, the Payment Streams module will emit a number of useful events in the on-chain transaction, which can be used by developers to capture and process data (for example, a websocket listening for Stream events in order to update their subscription database)</p><h2 id="viewing-a-stream-as-a-sender" tabindex="-1">Viewing a Stream (as a Sender) <a class="header-anchor" href="#viewing-a-stream-as-a-sender" aria-label="Permalink to &quot;Viewing a Stream (as a Sender)&quot;">​</a></h2><p>Once created, the UI will automatically update with the new stream information, which can be accessed via the &quot;As Sender&quot; tab.</p><p><img src="'+s+'" alt="View Stream" title="View Stream"></p><p>Each stream entry in the list contains all pertinent information regarding the stream, including:</p><ul><li>The Receiver wallet address (linked to the block explorer)</li><li>The current flow rate</li><li>The remaining deposit in the stream</li><li>The date and time the current deposit amount will reach zero</li><li>The date and time of the last claim made by the receiver</li><li>A real-time update of the current amount the receiver can claim/withdraw</li></ul><p>Viewing the stream as a sender displays a number of action buttons which the sender can undertake. These are covered in the relevant sections below.</p><h2 id="viewing-a-stream-as-a-receiver" tabindex="-1">Viewing a Stream (as a Receiver) <a class="header-anchor" href="#viewing-a-stream-as-a-receiver" aria-label="Permalink to &quot;Viewing a Stream (as a Receiver)&quot;">​</a></h2><p>As a Receiver, the data shown is identical to that of a sender. The only difference is the action buttons - only the Tx History and Claim buttons are available to the receiver.</p><p><img src="'+l+'" alt="View Stream" title="View Stream"></p><h2 id="view-tx-history-both" tabindex="-1">View Tx History (both) <a class="header-anchor" href="#view-tx-history-both" aria-label="Permalink to &quot;View Tx History (both)&quot;">​</a></h2><p>Clicking the &quot;Tx History&quot; button will open a modal listing the complete transaction history for the stream. This includes transactions broadcast by both the sender and the receiver.</p><p><img src="'+h+'" alt="Stream Tx History" title="Stream Tx History"></p><h2 id="modifying-a-stream-sender" tabindex="-1">Modifying a Stream (sender) <a class="header-anchor" href="#modifying-a-stream-sender" aria-label="Permalink to &quot;Modifying a Stream (sender)&quot;">​</a></h2><p>The sender can modify the stream in two ways - topping up the deposit, or adjusting the flow rate.</p><h2 id="top-up-the-deposit" tabindex="-1">Top up the Deposit <a class="header-anchor" href="#top-up-the-deposit" aria-label="Permalink to &quot;Top up the Deposit&quot;">​</a></h2><p>A sender may wish to top up the deposit to, for example, renew or extend a subscription. If the deposit zero time is close, a subscription service may send a reminder to a user that the subscription is about to expire. The user may then add more FUND to the stream in order to extend or renew the subscription.</p><p>Once the &quot;Top Up Deposit&quot; button is clicked, a dialog will appear allowing the user to enter the amount of FUND they wish to add to the stream. Clicking &quot;Send&quot; will prompt the wallet provider to ask the user to verify/sign and broadcast the Tx. The only requirements are that the sender wallet has enough FUND to cover the addition, and the tx fee.</p><p>If successful, the deposit zero time will be updated, and relevant events will be emitted by the blockchain.</p><h2 id="modify-the-flow-rate" tabindex="-1">Modify the Flow Rate <a class="header-anchor" href="#modify-the-flow-rate" aria-label="Permalink to &quot;Modify the Flow Rate&quot;">​</a></h2><p>A sender may wish to modify the flow rate of a stream if, for example, they are moving to a different subscription tier to a particular service.</p><p>Clicking the &quot;Update Flow Rate&quot; button will open a dialog prompting the user to enter the new details.</p><p><img src="'+m+'" alt="Update Stream" title="Update Stream"></p><p>The new flow rate will be calculated based on this data, and a new dialog will appear asking the user to confirm.</p><p><img src="'+c+'" alt="Update Stream" title="Update Stream"></p><p>This dialog will contain the new flow rate information, as well as a notice that the current claimable amount at the current flow rate will automatically be sent to the receiver before the flow rate is applied on-chain.</p><h2 id="cancelling-a-stream-sender" tabindex="-1">Cancelling a Stream (sender) <a class="header-anchor" href="#cancelling-a-stream-sender" aria-label="Permalink to &quot;Cancelling a Stream (sender)&quot;">​</a></h2><p>A sender can cancel a stream at any time. This will open a dialog asking the user to confirm, and display information about the cancellation process.</p><p><img src="'+d+'" alt="Cancel Stream" title="Cancel Stream"></p><p>Cancelling a stream will have the following effects:</p><ul><li>The claimable amount at the block time the cancellation transaction is processed will be sent to the receiver.</li><li>Any remaining deposit held in the stream will be refunded to the sender.</li><li>The stream will be deleted from the blockchain state</li></ul><h2 id="claiming-from-a-stream-receiver" tabindex="-1">Claiming from a Stream (receiver) <a class="header-anchor" href="#claiming-from-a-stream-receiver" aria-label="Permalink to &quot;Claiming from a Stream (receiver)&quot;">​</a></h2><p>A receiver can withdraw the current claimable amount at any time during the lifetime of a stream. This can be done as frequently as desired, or even only once the stream has ended (the deposit zero time is reached).</p><p><img src="'+p+'" alt="Claim Stream" title="Claim Stream"></p><p>Clicking the &quot;Claim&quot; button will open a dialog showing:</p><ul><li>The total amount currently claimable</li><li>The actual amount you will receive</li><li>The amount that will be sent to validators. This is currently a flat fee of 1% of the total claimable amount in this transaction. The fee can be modified via Governance.</li></ul>',51)])])}const T=t(u,[["render",f]]);export{S as __pageData,T as default};
